void solve(int CASE)
{
	ll n, m; cin >> n >> m;
	var a = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];

	var pos = vector<vector<int>>(n + 1);
	var tmp = vector<pll>();
	tmp.pb({ a[1],1 }); pos[1].pb(1);
	fa(r, 2, n) {
		for (var& [x, y] : tmp)x = Math::gcd(x, a[r]);
		tmp.pb({ a[r],r });
		var ntmp = vector<pll>{ tmp.back() };
		fb(i, vs(tmp) - 1, 0) 
			if (tmp[i].px != ntmp.back().px) 
				ntmp.pb(tmp[i]);
		reverse(all(ntmp));
		tmp = move(ntmp);
		for (const var& [_, id] : tmp)
			pos[r].pb(id);
	}

	while (m--) {
		ll l, r; cin >> l >> r;
		int ans = 0;
		fb(i, vs(pos[r]), 0) {
			if (pos[r][i] >= l)ans++;
			else break;
		}
		cout << ans << endl;
	}
	return;
}
